    buildPlayers() {
      const idx = {};
      const add = (name, team, val, season, kind) => {
        if (!idx[name]) idx[name] = { name: name, recs: [], goals: 0, assists: 0, seasons: {}, comps: {}, teams: {} };
        const p = idx[name];
        p.recs.push({ team: team, val: val, season: season.name, short: season.short, league: season.leagueName, order: season.order, kind: kind });
        if (kind === "goals") { p.goals += val; p.seasons[season.short] = (p.seasons[season.short] || 0) + val; }
        else p.assists += val;
        p.comps[season.leagueName] = 1; p.teams[team] = 1;
      };
      this.archive.forEach(L => L.seasons.forEach(s => {
        if (s.allTime) return;
        (s.topScorers || []).forEach(r => add(r[0], r[1], r[2], s, "goals"));
        (s.topAssists || []).forEach(r => add(r[0], r[1], r[2], s, "assists"));
      }));
      Object.values(idx).forEach(p => {
        p.nSeasons = Object.keys(p.seasons).length;
        p.nComps = Object.keys(p.comps).length;
        p.nTeams = Object.keys(p.teams).length;
        p.peak = Math.max(0, ...Object.values(p.seasons));
        const tg = {}; p.recs.forEach(r => { if (r.kind === "goals") tg[r.team] = (tg[r.team] || 0) + r.val; });
        p.mainTeam = Object.keys(tg).sort((a, b) => tg[b] - tg[a])[0] || p.recs[0].team;
      });
      Object.keys(this.rosters).forEach(team => this.rosters[team].forEach(nm => {
        if (!idx[nm]) idx[nm] = { name: nm, recs: [], goals: 0, assists: 0, seasons: {}, comps: {}, teams: {}, nSeasons: 0, nComps: 0, nTeams: 1, peak: 0, mainTeam: team };
      }));
      // Apply supplied assist totals to the player's own record (so they show in profile + comparison, not just the team tab)
      Object.keys(this.assistOverrides).forEach(team => Object.keys(this.assistOverrides[team]).forEach(nm => {
        if (!idx[nm]) idx[nm] = { name: nm, recs: [], goals: 0, assists: 0, seasons: {}, comps: {}, teams: { [team]: 1 }, nSeasons: 0, nComps: 0, nTeams: 1, peak: 0, mainTeam: team };
        idx[nm].assists = this.assistOverrides[team][nm];
      }));
      this.players = idx;
      this.playerNames = Object.keys(idx).sort((a, b) => idx[b].goals - idx[a].goals);
    }
  
    buildTeams() {
      const t = {};
      this.archive.forEach(L => L.seasons.forEach(s => {
        const rows = [];
        if (s.table) s.table.forEach(r => rows.push(r[0]));
        if (s.divisions) Object.values(s.divisions).forEach(d => d.forEach(r => rows.push(r[0])));
        if (s.groups) Object.values(s.groups).forEach(d => d.forEach(r => rows.push(r[0])));
        rows.forEach(nm => { if (!t[nm]) t[nm] = { comps: {} }; t[nm].comps[L.name] = 1; });
        (s.topScorers || []).forEach(r => { if (!t[r[1]]) t[r[1]] = { comps: {} }; t[r[1]].comps[L.name] = 1; });
      }));
      this.teamComps = t;
    }
  
